const items = $input.all();
const result = items
  .filter((item) => {
    if (item?.json?.Username && item?.json?.Password) {
      return item?.json["Account Status"] === "Active";
    }
    return false;
  })
  .map((item) => item?.json?.Username);
return { result };

// Fetch user input from the Webhook31 node
const userInput = $("Webhook31").all();

// Return the user input
return userInput;

const airtableData = $input.all().map((item) => item.json);
const webhookData = $("Webhook31")
  .all()
  .map((item) => item.json);

const matchedData = airtableData.filter((airtableItem) => {
  return webhookData.some((webhookItem) => webhookItem.id === airtableItem.id);
});

return matchedData.map((item) => ({ json: item }));
